using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load raw CSV and map "Yes"/"No" → bool Label
var rawData = mlContext.Data.LoadFromTextFile<CustomerDataRaw>(
    dataPath, hasHeader: true, separatorChar: ',');

var mappingPipeline = mlContext.Transforms.CustomMapping<CustomerDataRaw, LabelMapping>(
    (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
    contractName: null);

var dataView = mappingPipeline.Fit(rawData).Transform(rawData);

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// Evaluate — handle small datasets where test set may lack positive/negative class
var predictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}  F1: {metrics.F1Score:F4}  Accuracy: {metrics.Accuracy:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Warning: Dataset too small for reliable evaluation metrics. Add more training data.");
    var cvResults = mlContext.BinaryClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);
    var avgAccuracy = cvResults.Average(r => r.Metrics.Accuracy);
    Console.WriteLine($"Cross-validation average accuracy: {avgAccuracy:F4}");
}

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API is running");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
